The `debounce` function ensures a given function is only executed after a certain delay has passed since its last invocation.

```javascript
/**
 * Debounces a function to prevent it from being called too frequently.
 * @param {function} func The function to debounce.
 * @param {number} delay The minimum delay between invocations in milliseconds.
 * @returns {function} A debounced version of the input function.
 */
function debounce(func, delay) {
  let timeoutId;
  return function (...args) {
    if (timeoutId) {
      clearTimeout(timeoutId);
    }
    timeoutId = setTimeout(() => {
      func.apply(this, args);
    }, delay);
  };
}

// Example usage:
const debouncedLogger = debounce((message) => console.log(message), 500);
debouncedLogger("Hello"); // Will log "Hello" after 500ms
debouncedLogger("World"); // Will cancel the previous log and log "World" after 500ms
```
